// Config — editar acá si cambia el folder o el año
return [{
  json: {
    folderId: 'REPLACE_WITH_DREAN_PAUTA_FOLDER_ID',
    year: 2026,
  }
}];

// Parsea cada CSV y emite filas en formato planning_media.
//
// Asume filenames como 'Mes-Categoria.csv' (ej: Mayo-Refrigeracion.csv,
// Mayo-UGC.csv). El parser extrae mes + categoria del nombre, después
// busca dentro del CSV las columnas relevantes (Rol Of Comms, TouchPoint,
// Sistema, Formato & Channel, y la columna de inversión del mes).
//
// Diseño defensivo: tolerante a variaciones en nombres de columnas.

const MONTHS = {
  'enero':1,'febrero':2,'marzo':3,'abril':4,'mayo':5,'junio':6,
  'julio':7,'agosto':8,'septiembre':9,'octubre':10,'noviembre':11,'diciembre':12,
};

// Normalizar nombre de categoría — sacar guiones/underscores y mapear plurales
const normalizeCategoria = (raw) => {
  const s = (raw || '').replace(/[-_]/g, ' ').trim();
  const lower = s.toLowerCase();
  if (lower.startsWith('cocina')) return 'Cocina';
  if (lower.startsWith('refriger')) return 'Refrigeración';
  if (lower.startsWith('lavado')) return 'Lavado';
  if (lower.startsWith('brand')) return 'Brand';
  if (lower.startsWith('promo')) return 'Promoción';
  if (lower.startsWith('ugc')) return 'UGC';
  // Por default, capitalizar primera letra
  return s.charAt(0).toUpperCase() + s.slice(1).toLowerCase();
};

// CSV parser que respeta comillas y comas dentro de strings
const parseCSVLine = (line) => {
  const out = [];
  let cur = '';
  let inQ = false;
  for (let i = 0; i < line.length; i++) {
    const ch = line[i];
    if (ch === '"' && line[i+1] === '"') { cur += '"'; i++; }
    else if (ch === '"') { inQ = !inQ; }
    else if (ch === ',' && !inQ) { out.push(cur); cur = ''; }
    else { cur += ch; }
  }
  out.push(cur);
  return out.map(c => c.trim());
};

const parseCurrency = (v) => {
  if (v === null || v === undefined || v === '') return null;
  const s = String(v).trim();
  if (s === '-' || s === '$-' || s === '$ -' || s === '$0' || s === '$ 0') return 0;
  const cleaned = s.replace(/[\s$]/g, '').replace(/\./g, '').replace(',', '.');
  const n = Number(cleaned);
  return Number.isFinite(n) ? n : null;
};

const COSTO_PATTERNS = [/iibb/i, /percep/i, /cheque/i, /impuesto/i, /tech\s*fee/i, /comisi/i];
const esCosto = (formato) => formato && COSTO_PATTERNS.some(re => re.test(formato));

const SKIP_PATTERNS = [/^Total\s/i, /^Total$/i, /^Subtotal/i];
const esSkip = (sistema, formato) => {
  const txt = [sistema, formato].filter(Boolean).join(' ');
  return SKIP_PATTERNS.some(re => re.test(txt));
};

const config = $('Set Config').first().json;
const YEAR = config.year || 2026;

const output = [];

for (const item of $input.all()) {
  const binaryKey = Object.keys(item.binary || {})[0];
  if (!binaryKey) continue;
  const bin = item.binary[binaryKey];
  const filename = bin.fileName || item.json.name || '';

  // Parsear filename: Mes-Categoria.csv
  const m = filename.match(/^([A-Za-zÁÉÍÓÚáéíóúñÑ]+)[-_\s]+(.+?)\.csv$/i);
  if (!m) {
    console.warn(`Filename no matchea patrón Mes-Categoria.csv: ${filename}`);
    continue;
  }
  const mesRaw = m[1].toLowerCase().normalize('NFD').replace(/[̀-ͯ]/g, '');
  const mesNum = MONTHS[mesRaw];
  if (!mesNum) {
    console.warn(`Mes no reconocido en filename: ${filename} (mes=${mesRaw})`);
    continue;
  }
  const campania = normalizeCategoria(m[2]);
  const fecha = `${YEAR}-${String(mesNum).padStart(2, '0')}-01`;
  const mesCapitalized = mesRaw.charAt(0).toUpperCase() + mesRaw.slice(1);

  // Decodificar contenido del CSV
  const csvText = Buffer.from(bin.data, 'base64').toString('utf-8');
  const lines = csvText.split(/\r?\n/).filter(l => l.trim());
  if (lines.length < 2) {
    console.warn(`CSV sin filas de datos: ${filename}`);
    continue;
  }

  // Headers (línea 1)
  const headers = parseCSVLine(lines[0]);
  const idx = (...names) => {
    for (const n of names) {
      const i = headers.findIndex(h => h.toLowerCase() === n.toLowerCase());
      if (i >= 0) return i;
    }
    return -1;
  };

  const iRol     = idx('Rol Of Comms', 'Rol', 'Rol of Comms');
  const iTouch   = idx('TouchPoint', 'Touchpoint', 'Touch Point');
  const iSis     = idx('Sistema', 'Plataforma', 'Platform');
  const iFmt     = idx('Formato & Channel', 'Formato', 'Formato y Channel', 'Format');
  const iInvMes  = idx(mesCapitalized, mesRaw, mesCapitalized.toUpperCase());
  const iInvGen  = idx('Inversion', 'Inversión', 'Inv', 'Invertido', 'Total');

  // Si no hay columna del mes ni columna general → invalido
  if (iInvMes < 0 && iInvGen < 0) {
    console.warn(`No encontré columna de inversión en ${filename}. Headers: ${headers.join(' | ')}`);
    continue;
  }

  for (let i = 1; i < lines.length; i++) {
    const cols = parseCSVLine(lines[i]);
    if (cols.length === 0) continue;

    const rol     = iRol   >= 0 ? cols[iRol]   : '';
    const touch   = iTouch >= 0 ? cols[iTouch] : '';
    const sistema = iSis   >= 0 ? cols[iSis]   : '';
    const formato = iFmt   >= 0 ? cols[iFmt]   : '';
    const invStr  = iInvMes >= 0 ? cols[iInvMes] : (iInvGen >= 0 ? cols[iInvGen] : '');

    if (esSkip(sistema, formato)) continue;

    const inversion = parseCurrency(invStr);
    if (inversion === null || inversion === 0) continue;

    output.push({
      json: {
        fecha,
        campania,
        rol: rol || null,
        touchpoint: touch || null,
        sistema: sistema || null,
        formato: formato || null,
        inversion,
        tipo: esCosto(formato) ? 'costo' : 'media',
      },
    });
  }
}

return output;
